CATEGORIES = [
    ("👕 Футболки", "Футболки"),
    ("🧥 Свитшоты", "Свитшоты"),
    ("🤍 Худи", "Худи"),
    ("🛋 Подушки", "Подушки"),
    ("☕ Кружки", "Кружки"),
    ("👜 Сумки", "Сумки"),
    ("👔 Поло", "Поло"),
    ("👗 Платья", "Платья"),
    ("👚 Женская одежда", "Женская одежда"),
    ("🎨 Все принты", ""),
]


async def start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data.clear()
    kb = [[c[0]] for c in CATEGORIES]
    await update.message.reply_text(
        "👋 Добро пожаловать в *Wondershop*!\n\nНанесём ваш любимый принт на любой товар.\n\n👇 Выберите вид товара:",
        parse_mode="Markdown",
        reply_markup=ReplyKeyboardMarkup(kb, resize_keyboard=True, one_time_keyboard=True)
    )
    return CATEGORY


async def category(update: Update, context: ContextTypes.DEFAULT_TYPE):
    text = update.message.text
    cat_filter = ""
    for label, cat in CATEGORIES:
        if label == text:
            cat_filter = cat
            break
    url = f"{WEBAPP_URL}?cat={cat_filter}" if cat_filter else WEBAPP_URL
    context.user_data["selected_category"] = cat_filter
    kb = InlineKeyboardMarkup([[InlineKeyboardButton("🎨 Открыть каталог", web_app=WebAppInfo(url=url))]])
    cat_name = text.split(" ", 1)[1] if " " in text else text
    await update.message.reply_text(
        f"Открываю каталог *{cat_name}*!\n\nВыберите понравившийся принт:",
        parse_mode="Markdown",
        reply_markup=kb
    )


async def webapp_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    import json as _json
    logger.info("WebApp data received!")
    try:
        data = _json.loads(update.effective_message.web_app_data.data)
        logger.info(f"Data: {data}")
        pid = str(data.get("print_id", ""))
        p = PRODUCTS.get(pid)
        if p:
            context.user_data.update({
                "print_name": p["name"],
                "print_category": p.get("category", ""),
                "print_price": p.get("price", 0),
                "print_img": p.get("img", "")
            })
            kb = [SIZES[i:i+2] for i in range(0, len(SIZES), 2)]
            await update.message.reply_text(
                f"✅ Отличный выбор!\n\n🎨 Принт: *{p['name']}*\n📂 {p.get('category', '')}\n\nВыберите размер:",
                parse_mode="Markdown",
                reply_markup=ReplyKeyboardMarkup(kb, resize_keyboard=True, one_time_keyboard=True)
            )
            return SIZE
        else:
            await update.message.reply_text("Принт не найден. Попробуйте ещё раз /start")
    except Exception as e:
        logger.error(f"WebApp error: {e}")
        await update.message.reply_text("Ошибка. Попробуйте ещё раз /start")


async def size(update: Update, context: ContextTypes.DEFAULT_TYPE):
    c = update.message.text
    if c not in SIZES:
        kb = [SIZES[i:i+2] for i in range(0, len(SIZES), 2)]
        await update.message.reply_text("Выберите размер из списка 👇",
            reply_markup=ReplyKeyboardMarkup(kb, resize_keyboard=True, one_time_keyboard=True))
        return SIZE
    context.user_data["size"] = c
    await update.message.reply_text(
        "Сколько штук?\n\n_При заказе от 3 шт — доставка бесплатно! 🎁_",
        parse_mode="Markdown",
        reply_markup=ReplyKeyboardMarkup([["1","2","3"],["4","5","10"]], resize_keyboard=True, one_time_keyboard=True))
    return QUANTITY


async def quantity(update: Update, context: ContextTypes.DEFAULT_TYPE):
    try:
        qty = int(update.message.text)
        assert qty > 0
    except:
        await update.message.reply_text("Введите число, например: 1")
        return QUANTITY
    context.user_data["quantity"] = qty
    context.user_data["delivery"] = 0 if qty >= 3 else 15000
    await update.message.reply_text("Введите ваше имя:", reply_markup=ReplyKeyboardRemove())
    return NAME


async def name(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data["name"] = update.message.text
    await update.message.reply_text("Введите номер телефона:\n_Например: +998901234567_", parse_mode="Markdown")
    return PHONE


async def phone(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data["phone"] = update.message.text
    d = context.user_data
    qty = d.get("quantity", 1)
    price = d.get("print_price", 0)
    delivery = d.get("delivery", 15000)
    total = price * qty + delivery if price > 0 else delivery
    s = f"📋 *Проверьте заказ:*\n\n🎨 {d.get('print_name','-')}\n📂 {d.get('print_category','-')}\n📐 {d.get('size','-')}\n🔢 {qty} шт\n🚚 {'Бесплатно' if delivery==0 else '15 000 сум'}\n"
    if total > 0:
        s += f"💰 *{total:,} сум*\n\n".replace(",", " ")
    s += f"👤 {d.get('name','-')}\n📞 {d.get('phone','-')}\n\nВсё верно?"
    await update.message.reply_text(s, parse_mode="Markdown",
        reply_markup=ReplyKeyboardMarkup([["✅ Подтвердить","❌ Заново"]], resize_keyboard=True, one_time_keyboard=True))
    return CONFIRM


async def confirm(update: Update, context: ContextTypes.DEFAULT_TYPE):
    t = update.message.text
    if "Заново" in t:
        context.user_data.clear()
        return await start(update, context)
    if "Подтвердить" not in t:
        await update.message.reply_text("Выберите один из вариантов 👇")
        return CONFIRM
    d = context.user_data
    qty = d.get("quantity", 1)
    price = d.get("print_price", 0)
    delivery = d.get("delivery", 15000)
    total = price * qty + delivery if price > 0 else delivery
    msg = f"🔔 *НОВЫЙ ЗАКАЗ — Wondershop*\n\n🎨 {d.get('print_name','-')}\n📂 {d.get('print_category','-')}\n📐 {d.get('size','-')}\n🔢 {qty} шт\n"
    if total > 0:
        msg += f"💰 {total:,} сум\n".replace(",", " ")
    msg += f"👤 {d.get('name','-')}\n📞 {d.get('phone','-')}\n🆔 {update.effective_user.id}\n@{update.effective_user.username or 'нет'}"
    await context.bot.send_message(chat_id=ADMIN_CHAT_ID, text=msg, parse_mode="Markdown")
    img = d.get("print_img", "")
    if img:
        try:
            await context.bot.send_photo(chat_id=ADMIN_CHAT_ID, photo=img,
                caption=f"{d.get('print_name')} | {d.get('name')} {d.get('phone')}")
        except:
            pass
    await update.message.reply_text(
        f"✅ *Заказ принят!*\n\nСпасибо, {d.get('name')}! Свяжемся по {d.get('phone')} в течение 1 часа.\n⏱ Срок: 3-5 дней",
        parse_mode="Markdown", reply_markup=ReplyKeyboardRemove()
    )
    context.user_data.clear()
    return ConversationHandler.END


async def cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text("Отменено. /start чтобы начать заново.", reply_markup=ReplyKeyboardRemove())
    return ConversationHandler.END


def main():
    app = Application.builder().token(BOT_TOKEN).build()
    app.add_handler(MessageHandler(filters.StatusUpdate.WEB_APP_DATA, webapp_handler))
    conv = ConversationHandler(
        entry_points=[CommandHandler("start", start)],
        states={
            CATEGORY: [MessageHandler(filters.TEXT & ~filters.COMMAND, category)],
            SIZE:     [MessageHandler(filters.TEXT & ~filters.COMMAND, size)],
            QUANTITY: [MessageHandler(filters.TEXT & ~filters.COMMAND, quantity)],
            NAME:     [MessageHandler(filters.TEXT & ~filters.COMMAND, name)],
            PHONE:    [MessageHandler(filters.TEXT & ~filters.COMMAND, phone)],
            CONFIRM:  [MessageHandler(filters.TEXT & ~filters.COMMAND, confirm)],
        },
        fallbacks=[CommandHandler("cancel", cancel)],
    )
    app.add_handler(conv)
    app.run_polling(allowed_updates=Update.ALL_TYPES)


if __name__ == "__main__":
    import time
    time.sleep(3)
    main()
